mapper.select:
SELECT cs.id, cs.student_id AS studentId, cs.course_id AS courseId, DATE_FORMAT(cs.selection_time, '%Y-%m-%d %H:%i:%s') AS selectionTime, cs.status, c.course_no AS courseNo, c.name, c.credit, c.hours, c.teacher_id AS teacherId, t.teacher_name AS teacherName, c.semester, c.year, c.max_students AS maxStudents, c.day_of_week AS dayOfWeek, c.start_time AS startTime, c.end_time AS endTime, c.classroom, c.max_credits AS maxCredits, c.status AS courseStatus, c.description, c.study_nature AS studyNature, c.textbook, c.external_selection AS externalSelection, c.remark FROM course_selection cs LEFT JOIN course c ON cs.course_id = c.id LEFT JOIN teacher t ON c.teacher_id = t.id
AND cs.student_id = #{studentId}
AND cs.course_id = #{courseId}
AND cs.status = #{status}
ORDER BY cs.selection_time DESC
